# ───────────── SQL ДЛЯ СОЗДАНИЯ ТАБЛИЦ ─────────────
CREATE_TABLES_SQL = """
IF OBJECT_ID(N'dbo.health_results', N'U') IS NOT NULL
    DROP TABLE dbo.health_results;
IF OBJECT_ID(N'dbo.reference_values', N'U') IS NOT NULL
    DROP TABLE dbo.reference_values;

CREATE TABLE health_results (
    id INT IDENTITY(1,1) PRIMARY KEY,
    person_name NVARCHAR(100) NOT NULL,
    test_date DATETIME NOT NULL,
    system_name NVARCHAR(200) NOT NULL,
    parameter_name NVARCHAR(255) NOT NULL,
    parameter_value NVARCHAR(100) NOT NULL
);

CREATE TABLE reference_values (
    id INT IDENTITY(1,1) PRIMARY KEY,
    parameter_name NVARCHAR(255) COLLATE Latin1_General_100_CI_AS_SC NOT NULL,
    system_name NVARCHAR(200) COLLATE Latin1_General_100_CI_AS_SC NOT NULL,
    norm_min DECIMAL(10,3), norm_max DECIMAL(10,3),
    minor_high_min DECIMAL(10,3), minor_high_max DECIMAL(10,3),
    significant_high_min DECIMAL(10,3), significant_high_max DECIMAL(10,3),
    severe_high_min DECIMAL(10,3), severe_high_max DECIMAL(10,3),
    minor_low_min DECIMAL(10,3), minor_low_max DECIMAL(10,3),
    significant_low_min DECIMAL(10,3), significant_low_max DECIMAL(10,3),
    severe_low_min DECIMAL(10,3), severe_low_max DECIMAL(10,3),
    CONSTRAINT UQ_param_system UNIQUE (parameter_name, system_name)
);
"""

