def get_connection():
    """Устанавливает соединение с SQL Server"""
    try:
        conn_str = (
            f"DRIVER={DB_CONFIG['driver']};"
            f"SERVER={DB_CONFIG['server']};"
            f"DATABASE={DB_CONFIG['database']};"
            f"UID={DB_CONFIG['username']};"
            f"PWD={DB_CONFIG['password']};"
        )
        return pyodbc.connect(conn_str)
    except Exception as e:
        print(f"❌ Ошибка подключения к БД: {e}")
        return None

def main():
    print("=" * 60)
    print(" ИНИЦИАЛИЗАЦИЯ БАЗЫ ДАННЫХ HEALTH_DB")
    print("=" * 60)
    
    conn = get_connection()
    if not conn:
        return

    try:
        cursor = conn.cursor()
        
        # 1. Создаём таблицы (DROP + CREATE)
        print("\n🛠 Создание таблиц...")
        cursor.execute(CREATE_TABLES_SQL)
        conn.commit()
        print("✅ Таблицы health_results и reference_values успешно созданы/пересозданы.")
        
        # 2. Очищаем reference_values (на случай, если кто-то добавил данные вручную)
        print("\n🧹 Очистка таблицы reference_values...")
        cursor.execute("DELETE FROM reference_values")
        conn.commit()
        
        # 3. Вставляем референсные значения
        print("📥 Загрузка референсных значений...")
        insert_query = """
            INSERT INTO reference_values (parameter_name, system_name, norm_min, norm_max, minor_high_min, minor_high_max, significant_high_min, significant_high_max, severe_high_min, severe_high_max, minor_low_min, minor_low_max, significant_low_min, significant_low_max, severe_low_min, severe_low_max)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """
        try:
            cursor.executemany(insert_query, REFERENCE_DATA)
            conn.commit() 
        except Exception as e:
            print(f"  ⚠️ Ошибка вставки: {e}")
            raise
        
        # 4. Считаем количество записей
        cursor.execute("SELECT COUNT(*) FROM reference_values")
        count = cursor.fetchone()[0]
        
        print(f"\n🎉 Инициализация завершена успешно!")
        print(f"✅ Загружено {count} референсных значений")
        cursor.close()
        
    except Exception as e:
        print(f"\n❌ Критическая ошибка: {e}")
    finally:
        if conn:
            conn.close()
            print("🔌 Соединение с БД закрыто.")

if __name__ == "__main__":
    main()